# ===== HTML GENERATION =====

def demand_chip(d):
    cls = {'hot':'d-hot','warm':'d-warm','flat':'d-flat','declining':'d-declining'}[d]
    lbl = {'hot':'Hot','warm':'Warm','flat':'Flat','declining':'Declining'}[d]
    return f'<span class="{cls}">{lbl}</span>'

def gen_tech_tags(tech):
    parts = []
    for label, items in tech:
        parts.append(f'<span style="font-size:10px;font-weight:700;color:var(--text-dim);margin-right:2px">{e(label)}:</span>')
        for item in items.split(', '):
            parts.append(f'<span class="tech-tag">{e(item.strip())}</span>')
        parts.append('<br style="margin:2px 0">')
    return ''.join(parts)

def gen_details(ind):
    num=ind['num']; name=ind['name']; tier=ind['tier']; demand=ind['demand']; wage=ind['wage']
    sys_html='<ul>'+''.join(f'<li>{e(s)}</li>' for s in ind['systems'])+'</ul>'
    proj_html='<ul>'+''.join(f'<li>{e(p)}</li>' for p in ind['projects'])+'</ul>'
    emp_rows=''.join(f'<tr><td style="font-weight:600;white-space:nowrap;padding:4px 8px;border-bottom:1px solid var(--border)">{e(pv)}</td><td style="padding:4px 8px;color:var(--text-dim);border-bottom:1px solid var(--border)">{e(em)}</td></tr>' for pv,em in ind['provinces'])
    emp_html=f'<table style="width:100%;border-collapse:collapse;font-size:11px"><thead><tr><th style="text-align:left;padding:4px 8px;font-size:10px;font-weight:700;color:var(--text-dim);text-transform:uppercase;border-bottom:2px solid var(--border)">Province</th><th style="text-align:left;padding:4px 8px;font-size:10px;font-weight:700;color:var(--text-dim);text-transform:uppercase;border-bottom:2px solid var(--border)">Named employers</th></tr></thead><tbody>{emp_rows}</tbody></table>'
    tech_html=gen_tech_tags(ind['tech'])
    comp_html='<ul>'+''.join(f'<li>{e(c)}</li>' for c in ind['compliance'])+'</ul>'
    entry_html='<ul>'+''.join(f'<li>{e(n)}</li>' for n in ind['entry_notes'])+'</ul>'
    return f'''<details class="ind-details">
  <summary>
    <span class="ind-num">{e(num)}</span>
    <span class="sum-label">{e(name)}</span>
    {demand_chip(demand)}
    <span class="t-chip">{e(tier)}</span>
    <span style="font-size:10px;color:var(--text-dim);margin-left:auto;white-space:nowrap">{e(wage)}</span>
  </summary>
  <div class="expand-content">
    <div class="ind-grid">
      <div class="ind-card"><div class="ic-head">Systems &amp; Products</div><div class="ic-body">{sys_html}</div></div>
      <div class="ind-card"><div class="ic-head">Project Types</div><div class="ic-body">{proj_html}</div></div>
      <div class="ind-card"><div class="ic-head">Employers by Province</div><div class="ic-body" style="padding:0">{emp_html}</div></div>
      <div class="ind-card"><div class="ic-head">Tech Stack Signals</div><div class="ic-body">{tech_html}</div></div>
      <div class="ind-card"><div class="ic-head">Compliance &amp; Regulatory</div><div class="ic-body">{comp_html}</div></div>
      <div class="ind-card"><div class="ic-head">Entry Notes</div><div class="ic-body">{entry_html}</div></div>
    </div>
  </div>
</details>'''

def gen_vertical_section(vslug, vname, vcount, vsub, industries):
    rows=''
    for ind in industries:
        rows+=f'<tr><td style="font-weight:500">{e(ind["num"])} {e(ind["name"])}</td><td>{e(ind["tier"])}</td><td>{demand_chip(ind["demand"])}</td><td style="white-space:nowrap">{e(ind["wage"])}</td><td style="text-align:center">{ind["entry"]}/5</td><td style="font-size:10px">{e(ind["top_employers"])}</td><td style="font-size:10px">{e(ind["key_reg"])}</td></tr>'
    details_html='\n'.join(gen_details(ind) for ind in industries)
    return f'''<h2 id="{vslug}">{e(vname)} ({vcount})</h2>
<p class="section-sub">{e(vsub)}</p>
<div class="tbl-wrap ind-summary-tbl">
  <table class="xref-table">
    <thead><tr><th>Industry</th><th>Tier</th><th>Demand</th><th>Wage band</th><th>Entry</th><th>Top employers</th><th>Key regulation</th></tr></thead>
    <tbody>{rows}</tbody>
  </table>
</div>
{details_html}'''

